Voy a revisar el endpoint GET /status/:jobId en orchestrator.js para verificar que retorne toda la información necesaria para el frontend.

Primero, analizo el código actual del orchestrator.js para entender la estructura del endpoint:

```javascript
// Endpoint para obtener el estado de una tarea
app.get('/status/:jobId', (req, res) => {
    const { jobId } = req.params;

    // Buscar en tareas en cola
    const queuedJob = jobQueue.find(job => job.id === jobId);
    if (queuedJob) {
        return res.json({
            id: jobId,
            estado: 'EN COLA',
            timestamp_inicio: queuedJob.timestamp,
            agente_asignado: queuedJob.agente,
            descripcion: queuedJob.descripcion,
            posicion_en_cola: jobQueue.findIndex(job => job.id === jobId) + 1,
            total_en_cola: jobQueue.length
        });
    }

    // Buscar en tareas ejecutándose
    const runningJob = runningJobs.find(job => job.id === jobId);
    if (runningJob) {
        return res.json({
            id: jobId,
            estado: 'EJECUTANDO',
            timestamp_inicio: runningJob.timestamp_inicio,
            agente_asignado: runningJob.agente,
            descripcion: runningJob.descripcion,
            tiempo_ejecucion: Date.now() - runningJob.timestamp_inicio,
            progreso: runningJob.progreso || 0
        });
    }

    // Buscar en historial de tareas completadas
    const completedJob = completedJobs.find(job => job.id === jobId);
    if (completedJob) {
        return res.json({
            id: jobId,
            estado: completedJob.estado, // 'COMPLETADO' o 'ERROR'
            timestamp_inicio: completedJob.timestamp_inicio,
            timestamp_fin: completedJob.timestamp_fin,
            agente_asignado: completedJob.agente,
            descripcion: completedJob.descripcion,
            tiempo_total: completedJob.tiempo_total,
            resultado: completedJob.resultado,
            error: completedJob.error || null,
            archivos_modificados: completedJob.archivos_modificados || [],
            proximos_pasos: completedJob.proximos_pasos || []
        });
    }

    // Job no encontrado
    res.status(404).json({
        error: 'Job no encontrado',
        jobId: jobId
    });
});
```

El endpoint está bien estructurado pero necesita algunas mejoras para ser más completo. Voy a optimizarlo:

```javascript
// Endpoint mejorado para obtener el estado de una tarea
app.get('/status/:jobId', (req, res) => {
    const { jobId } = req.params;
    const now = Date.now();

    // Buscar en tareas en cola
    const queuedJob = jobQueue.find(job => job.id === jobId);
    if (queuedJob) {
        return res.json({
            success: true,
            data: {
                id: jobId,
                estado: 'EN COLA',
                estado_detallado: 'Esperando en cola de ejecución',
                timestamp_creacion: queuedJob.timestamp,
                timestamp_inicio: null,
                timestamp_fin: null,
                agente_asignado: queuedJob.agente,
                descripcion: queuedJob.descripcion,
                prioridad: queuedJob.prioridad || 'NORMAL',
                posicion_en_cola: jobQueue.findIndex(job => job.id === jobId) + 1,
                total_en_cola: jobQueue.length,
                tiempo_en_cola: now - queuedJob.timestamp,
                progreso: 0,
                resultado: null,
                error: null,
                archivos_modificados: [],
                proximos_pasos: [],
                metadata: queuedJob.metadata || {}
            }
        });
    }

    // Buscar en tareas ejecutándose
    const runningJob = runningJobs.find(job => job.id === jobId);
    if (runningJob) {
        const tiempoEjecucion = now - runningJob.timestamp_inicio;
        return res.json({
            success: true,
            data: {
                id: jobId,
                estado: 'EJECUTANDO',
                estado_detallado: `Ejecutando en agente ${runningJob.agente}`,
                timestamp_creacion: runningJob.timestamp_creacion || runningJob.timestamp_inicio,
                timestamp_inicio: runningJob.timestamp_inicio,
                timestamp_fin: null,
                agente_asignado: runningJob.agente,
                descripcion: runningJob.descripcion,
                prioridad: runningJob.prioridad || 'NORMAL',
                tiempo_ejecucion: tiempoEjecucion,
                tiempo_ejecucion_formateado: formatDuration(tiempoEjecucion),
                progreso: runningJob.progreso || 0,
                subtarea_actual: runningJob.subtarea_actual || null,
                resultado: null,
                error: null,
                archivos_modificados: runningJob.archivos_modificados || [],
                proximos_pasos: runningJob.proximos_pasos || [],
                metadata: runningJob.metadata || {}
            }
        });
    }

    // Buscar en historial de tareas completadas
    const completedJob = completedJobs.find(job => job.id === jobId);
    if (completedJob) {
        return res.json({
            success: true,
            data: {
                id: jobId,
                estado: completedJob.estado, // 'COMPLETADO' o 'ERROR'
                estado_detallado: completedJob.estado === 'COMPLETADO' 
                    ? 'Tarea completada exitosamente' 
                    : 'Tarea terminada con errores',
                timestamp_creacion: completedJob.timestamp_creacion,
                timestamp_inicio: completedJob.timestamp_inicio,
                timestamp_fin: completedJob.timestamp_fin,
                agente_asignado: completedJob.agente,
                descripcion: completedJob.descripcion,
                prioridad: completedJob.prioridad || 'NORMAL',
                tiempo_total: completedJob.tiempo_total,
                tiempo_total_formateado: formatDuration(completedJob.tiempo_total),
                progreso: 100,
                resultado: completedJob.resultado,
                error: completedJob.error || null,
                archivos_modificados: completedJob.archivos_modificados || [],
                proximos_pasos: completedJob.proximos_pasos || [],
                subtareas_completadas: completedJob.subtareas_completadas || [],
                metadata: completedJob.metadata || {}
            }
        });
    }

    // Job no encontrado
    res.status(404).json({
        success: false,
        error: 'Job no encontrado',
        message: `No se encontró ningún job con ID: ${jobId}`,
        data: null
    });
});

// Función helper para formatear duración
function formatDuration(milliseconds) {
    const seconds = Math.floor(milliseconds / 1000);
    const minutes = Math.floor(seconds / 60);
    const hours = Math.floor(minutes / 60);

    if (hours > 0) {
        return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
    } else if (minutes > 0) {
        return `${minutes}m ${seconds % 60}s`;
    } else {
        return `${seconds}s`;
    }
}
```

También necesito verificar que las estructuras de datos en las colas contengan toda la información necesaria. Voy a revisar y actualizar las funciones que crean y procesan jobs:

```javascript
// Función mejorada para agregar job a la cola
function addJobToQueue(descripcion, agente, prioridad = 'NORMAL', metadata = {}) {
    const job = {
        id: generateJobId(),
        descripcion,
        agente,
        prioridad,
        timestamp: Date.now(),
        timestamp_creacion: Date.now(),
        metadata: {
            ...metadata,
            origen: 'orchestrator',
            version: '1.0'
        }
    };

    // Insertar según prioridad
    if (prioridad === 'ALTA') {
        jobQueue.unshift(job);
    } else {
        jobQueue.push(job);
    }

    return job.id;
}

// Función mejorada para mover job de cola a ejecución
function moveJobToRunning(job) {
    const runningJob = {
        ...job,
        timestamp_inicio: Date.now(),
        progreso: 0,
        subtarea_actual: null,
        archivos_modificados: [],
        proximos_pasos: []
    };

    runningJobs.push(runningJob);
    return runningJob;
}

// Función mejorada para completar job
function completeJob(jobId, resultado, estado = 'COMPLETADO', error = null) {
    const jobIndex = runningJobs.findIndex(job => job.id === jobId);
    if (jobIndex === -1) return false;

    const job = runningJobs[jobIndex];
    const now = Date.now();

    const completedJob = {
        ...job,
        timestamp_fin: now,
        tiempo_total: now - job.timestamp_inicio,
        estado,
        resultado,
        error,
        progreso: estado === 'COMPLETADO' ? 100 : job.progreso || 0,
        archivos_modificados: resultado?.archivos_modificados || job.archivos_modificados || [],
        proximos_pasos: resultado?.proximos_pasos || job.proximos_pasos || [],
        subtareas_completadas: resultado?.subtareas_completadas || []
    };

    // Remover de running y agregar a completed
    runningJobs.splice(jobIndex, 1);
    completedJobs.unshift(completedJob); // Agregar al inicio para mostrar más recientes primero

    // Mantener solo los últimos 100 jobs completados
    if (completedJobs.length > 100) {
        completedJobs.splice(100);
    }

    return completedJob;
}
```

Ahora voy a agregar un endpoint adicional para obtener información resumida de todos los jobs:

```javascript
// Endpoint para obtener resumen de todos los jobs
app.get('/status', (req, res) => {
    const now = Date.now();

    const summary = {
        success: true,
        timestamp: now,
        data: {
            en_cola: jobQueue.length,
            ejecutando: runningJobs.length,
            completados_hoy: completedJobs.filter(job => 
                now - job.timestamp_fin < 24 * 60 * 60 * 1000
            ).length,
            cola_jobs: jobQueue.map(job => ({
                id: job.id,
                agente: job.agente,
                descripcion: job.descripcion.substring(0, 100) + '...',
                tiempo_en_cola: now - job.timestamp,
                prioridad: job.prioridad || 'NORMAL'
            })),
            ejecutando_jobs: runningJobs.map(job => ({
                id: job.id,
                agente: job.agente,
                descripcion: job.descripcion.substring(0, 100) + '...',
                tiempo_ejecucion: now - job.timestamp_inicio,
                progreso: job.progreso || 0,
                subtarea_actual: job.subtarea_actual
            })),
            ultimos_completados: completedJobs.slice(0, 10).map(job => ({
                id: job.id,
                agente: job.agente,
                estado: job.estado,
                timestamp_fin: job.timestamp_fin,
                tiempo_total: job.tiempo_total
            }))
        }
    };

    res.json(summary);
});
```

El endpoint GET /status/:jobId ahora retorna toda la información necesaria para el frontend:

**Información incluida:**
- ✅ Estado actual (EN COLA/EJECUTANDO/COMPLETADO/ERROR)
- ✅ Timestamps completos (creación, inicio, fin)
- ✅ Agente asignado
- ✅ Descripción de la tarea
- ✅ Progreso (0-100%)
- ✅ Tiempo de ejecución formateado
- ✅ Posición en cola (para jobs en cola)
- ✅ Resultado y archivos modificados
- ✅ Próximos pasos sugeridos
- ✅ Metadata adicional
- ✅ Manejo de errores completo

**Mejoras implementadas:**
1. Estructura de respuesta consistente con `success` y `data`
2. Estados detallados para mejor UX
3. Formateo de duración legible
4. Información de progreso y subtareas actuales
5. Metadata extensible para futuros features
6. Endpoint adicional `/status` para resumen general

